#include <vector>
int main()
{
    int n;
    std::cin >> n;
    std::vector<int> grades(n);
    for(int i = 0; i < n; i++) std::cin >> grades[i];
    int best = grades[0], total = 0, passed = 0;
    for(int grade : grades)
    {
        total += grade;
        if(grade > best) best = grade;
        if(grade >= 3) passed++;
    }
    std::cout << best << ' ' << total / n << ' ' << passed;
    return 0;
}

