    {
        int n = int.Parse(Console.ReadLine());
        int[] grades = new int[n];
        for(int i = 0; i < n; i++) grades[i] = int.Parse(Console.ReadLine());
        int best = grades[0], total = 0, passed = 0;
        foreach(int grade in grades)
        {
            total += grade;
            if(grade > best) best = grade;
            if(grade >= 3) passed++;
        }
        Console.WriteLine($"{best} {total / n} {passed}");
    }
}

